// Stations for Rosario / Gran Rosario / Paraná corridor / Villa Constitución.
// Keep ids aligned with data/fixtures/layer-snapshot.sample.json.
const stations = [
  { external_id: 'wx-rosario-centro',      name: 'Rosario Centro',           lon: -60.6393, lat: -32.9468 },
  { external_id: 'wx-san-lorenzo',         name: 'San Lorenzo',              lon: -60.7333, lat: -32.7459 },
  { external_id: 'wx-granadero-baigorria', name: 'Granadero Baigorria',      lon: -60.6794, lat: -32.8569 },
  { external_id: 'wx-villa-g-galvez',      name: 'Villa Gobernador Gálvez',  lon: -60.6044, lat: -33.0256 },
  { external_id: 'wx-funes',               name: 'Funes',                    lon: -60.8103, lat: -32.9211 },
  { external_id: 'wx-villa-constitucion',  name: 'Villa Constitución',       lon: -60.3297, lat: -33.2329 },
];
return stations.map(s => ({ json: { ...s, run_key: $execution.id } }));

// Shape each API response into one observation row matching
// docs/layer-snapshot-contract.md value keys.
// Open-Meteo returns times like '2026-06-09T12:00' (UTC, no seconds/Z).
const iso = (t) => (t.endsWith('Z') ? t : t + ':00Z');
const station = $('Define stations').item.json;
const wx = $('Fetch Open-Meteo forecast').item.json.current;
const aq = $('Fetch Open-Meteo air quality').item.json.current;
const rows = [];
if (wx) {
  rows.push({ source_id: 'open-meteo', layer: 'weather', external_ref: station.external_id,
    observed_at: iso(wx.time), lon: station.lon, lat: station.lat,
    values: { temperature_c: wx.temperature_2m, relative_humidity_pct: wx.relative_humidity_2m,
      wind_speed_kmh: wx.wind_speed_10m, wind_direction_deg: wx.wind_direction_10m,
      precipitation_mm: wx.precipitation } });
}
if (aq) {
  rows.push({ source_id: 'open-meteo-air-quality', layer: 'air_quality', external_ref: station.external_id.replace('wx-', 'aq-'),
    observed_at: iso(aq.time), lon: station.lon, lat: station.lat,
    values: { pm2_5_ugm3: aq.pm2_5, pm10_ugm3: aq.pm10 } });
}
return rows.map(r => ({ json: { ...r, station, run_key: station.run_key } }));

