UPDATE digital_twin.ingestion_runs
SET status = 'success', finished_at = now(), records_ingested = records_ingested + 1
WHERE source_id = 'open-meteo' AND run_key = $1;

UPDATE digital_twin.ingestion_runs
SET status = 'error', finished_at = now(), error_message = $2
WHERE source_id = 'open-meteo' AND run_key = $1;
